import Bio.Data
from Bio.Data import CodonTable

print(CodonTable.standard_rna_table)
print(CodonTable.standard_rna_table.forward_table["UUU"])
print(type(CodonTable.standard_rna_table.forward_table["UUU"]))

def encoder(s):
    recoded = s
    # two pointers 
    # one at 0, one at 2 
    point1 = 0
    point2 = 3
    new_string = ""
        
    for x in range(len(recoded)):
        splice = recoded[point1:point2]
        try:
            new_string = new_string + CodonTable.standard_rna_table.forward_table[splice]
            if len(recoded) % 3 == 0:
                point1 = point1 + 3
                point2 = point2 + 3
            else:
                try:
                    point1 = point1 + 3
                    point2 = point2 + 3
                except:
                    break
                    # rem = len(recoded) % 3
                    # point1 = point1 + 3 
                    # point2 = point2 + rem
        except:
            break
    
    
    
    return new_string

print(encoder(""))